#include <iostream>
#include <string>
#include <algorithm>
#include <climits>

using namespace std;

bool isPalindrome(const string& str) {
    int left = 0;
    int right = str.size() - 1;
    while (left < right) {
        if (str[left++] != str[right--]) {
            return false;
        }
    }
    return true;
}

int minCutsForDifferentPalindrome(string s) {
    int n = s.size();
    int ans = INT_MAX;

    // Try cutting at every possible position except the last
    for (int i = 1; i < n; ++i) {
        string p1 = s.substr(0, i);
        string p2 = s.substr(i);

        // All possible concatenations
        string candidate1 = p1 + p2;
        string candidate2 = p2 + p1;
        string candidate3 = p1 + reverseString(p2);
        string candidate4 = p2 + reverseString(p1);

        if (isPalindrome(candidate1) && candidate1 != s) {
            ans = min(ans, i);
        }
        if (isPalindrome(candidate2) && candidate2 != s) {
            ans = min(ans, i);
        }
        if (isPalindrome(candidate3) && candidate3 != s) {
            ans = min(ans, i);
        }
        if (isPalindrome(candidate4) && candidate4 != s) {
            ans = min(ans, i);
        }
    }

    return ans == INT_MAX ? -1 : ans;
}

string reverseString(const string& str) {
    string rev(str.rbegin(), str.rend());
    return rev;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    cout.tie(nullptr);

    string s;
    cin >> s;

    int result = minCutsForDifferentPalindrome(s);
    if (result == -1) {
        cout << "Impossible" << endl;
    } else {
        cout << result << endl;
    }

    return 0;
}

