int solve(int n, int m, const vector<string>& floors) {
    int count = 0;

    for (const auto& floor : floors) {
        for (size_t i = 0; i < floor.size(); i += 2) {
            if (floor[i] == '1' || floor[i + 1] == '1') {
                ++count;
                break;
            }
