bool can(ll D, const vll& a, ll x, ll k) {
    vector<pll> intervals;
    for (ll ai : a) {
        ll L = ai - D + 1;
        ll R = ai + D - 1;
        if (L <= R) intervals.emplace_back(L, R);
    }
    sort(all(intervals));
    vector<pll> merged;
    for (auto& p : intervals) {
        if (merged.empty() || p.first > merged.back().second + 1) {
            merged.pb(p);
        } else {
            merged.back().second = max(merged.back().second, p.second);
        }
    }
    ll forbidden = 0;
    for (auto& p : merged) {
        ll L = max(0LL, p.first);
        ll R = min(x, p.second);
        if (L <= R) forbidden += R - L + 1;
    }
    ll allowed = (x + 1) - forbidden;
    return allowed >= k;
}

void solve() {
    ll n, k, x;
    cin >> n >> k >> x;
    vll a(n);
    for (ll i = 0; i < n; ++i) cin >> a[i];
    sort(all(a));
    ll lo = 0, hi = x;
    while (lo < hi) {
        ll mid = (lo + hi + 1) / 2;
        if (can(mid, a, x, k)) lo = mid;
        else hi = mid - 1;
    }
    ll D = lo;
    vector<pll> intervals;
    for (ll ai : a) {
        ll L = ai - D + 1;
        ll R = ai + D - 1;
        if (L <= R) intervals.emplace_back(L, R);
    }
    sort(all(intervals));
    vector<pll> merged;
    for (auto& p : intervals) {
        if (merged.empty() || p.first > merged.back().second + 1) {
            merged.pb(p);
        } else {
            merged.back().second = max(merged.back().second, p.second);
        }
    }
    vector<pll> allowed;
    ll prev = 0;
    for (auto& p : merged) {
        ll L = max(0LL, p.first);
        ll R = min(x, p.second);
        if (L > prev) allowed.emplace_back(prev, L - 1);
        prev = max(prev, R + 1);
    }
    if (prev <= x) allowed.emplace_back(prev, x);
    vll ans;
    for (auto& p : allowed) {
        for (ll i = p.first; i <= p.second && sz(ans) < k; ++i) {
            ans.pb(i);
        }
        if (sz(ans) == k) break;
    }
    for (ll i = 0; i < k; ++i) {
        cout << ans[i] << " \n"[i == k - 1];
    }
}

int main() {
    fastio;
