#include <bits/stdc++.h>
using namespace std;

#define fastio ios::sync_with_stdio(false); cin.tie(nullptr)

void solve(int n, int k, int x, vector<int>& a) {
    sort(a.begin(), a.end());

    auto canPlace = [&](int d) -> bool {
        vector<bool> placed(n + 1, false);
        for (int i = 0; i < n; ++i) {
            if (!placed[i]) {
                int j = i;
                while (j < n && a[j] <= a[i] + d) {
                    placed[j++] = true;
                }
            }
        }
        return count(placed.begin(), placed.end(), true) >= k;
    };

    int low = 0, high = x, ans = -1;
    while (low <= high) {
        int mid = (low + high) / 2;
        if (canPlace(mid)) {
            ans = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    if (ans == -1) {
        cout << "NO\n";
        return;
    }

    vector<int> teleports;
    for (int i = 0; i < n;) {
        int pos = a[i];
        while (i < n && a[i] <= pos + ans) {
            ++i;
        }
        teleports.push_back(pos + ans);
    }

    // Ensure we have exactly k teleports
    teleports.resize(k);
    sort(teleports.begin(), teleports.end());

    for (int p : teleports) {
        cout << p << " ";
    }
    cout << "\n";
}

int main() {
    fastio;
    int t;
    cin >> t;
    while (t--) {
        int n, k, x;
        cin >> n >> k >> x;
        vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            cin >> a[i];
        }
        solve(n, k, x, a);
    }
    return 0;
}

