    for (int i = 0; i < n; ++i) {
        string row;
        cin >> row;
        for (int j = 0; j < n; ++j) {
            if (row[j] == '1') {
                adj[i].push_back(j);
                indegree[j]++;
            }
        }
    }

    queue<int> topoQueue;
    for (int i = 0; i < n; ++i) {
        if (indegree[i] == 0) {
            topoQueue.push(i);
        }
    }

    vector<int> topoOrder;
    while (!topoQueue.empty()) {
        int u = topoQueue.front();
        topoQueue.pop();
        topoOrder.push_back(u);

        for (int v : adj[u]) {
            if (--indegree[v] == 0) {
                topoQueue.push(v);
            }
        }
    }

    // Topological order exists because the graph is acyclic
    cout << topoOrder.size() << endl;
    for (int i : topoOrder) {
        cout << i + 1 << " ";
    }
    cout << endl;
}

