bool isValid(vector<int>& selected, int min_dist) {
    int n = selected.size();
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (abs(selected[i] - selected[j]) < min_dist) return false;
        }
    }
    return true;
}

int solve(int n, int m) {
    for (int i = 1; i <= n; ++i) adj[i].clear();
    memset(deg, 0, sizeof(deg));

    for (int i = 1; i <= m; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].pb(v);
        adj[v].pb(u);
        deg[u]++;
        deg[v]++;
    }

    vector<int> selected;
    for (int i = 1; i <= n; ++i) {
        if (deg[i] == 1 && !selected.empty()) {
            bool covered = false;
            for (int j : selected) {
                if (adj[i][0] == j || adj[i][1] == j) {
                    covered = true;
                    break;
                }
            }
            if (!covered) {
                selected.pb(i);
            }
        } else if (deg[i] > 1) {
            selected.pb(i);
        }
    }

    sort(selected.begin(), selected.end());
    reverse(selected.begin(), selected.end());

    int lo = 1, hi = n;
    while (lo < hi) {
        int mid = (lo + hi + 1) / 2;
        if (isValid(selected, mid)) {
            lo = mid;
        } else {
            hi = mid - 1;
        }
    }

    return lo;
}

