using namespace std;

struct Item {
    string name;
    string cls;
    int atk, def, res, size;
    vector<string> residents;
};

struct Resident {
    string name, type, home;
    int bonus;
};

bool compareResidentByBonus(const Resident& a, const Resident& b) {
    return a.bonus > b.bonus;
}

void moveResident(vector<Item>& items, string fromItemName, string toItemName, string residentName) {
    auto& fromItem = *find_if(items.begin(), items.end(), [&](const Item& i){ return i.name == fromItemName; });
    auto& toItem = *find_if(items.begin(), items.end(), [&](const Item& i){ return i.name == toItemName; });

    auto it = find(fromItem.residents.begin(), fromItem.residents.end(), residentName);
    if (it != fromItem.residents.end()) {
        fromItem.residents.erase(it);
        toItem.residents.push_back(residentName);
    }
}

void maximizeWeaponAttack(vector<Item>& items, vector<Resident>& residents) {
    sort(residents.begin(), residents.end(), compareResidentByBonus);

    for (auto& item : items) {
        if (item.cls == "weapon") {
            for (int i = 0; i < min((int)residents.size(), item.size); ++i) {
                moveResident(items, residents[i].home, item.name, residents[i].name);
            }
        }
    }
}

void maximizeArmorAndOrb(vector<Item>& items, vector<Resident>& residents) {
    auto& weapon = *find_if(items.begin(), items.end(), [](const Item& i){ return i.cls == "weapon"; });
    auto& armor = *find_if(items.begin(), items.end(), [](const Item& i){ return i.cls == "armor"; });
    auto& orb = *find_if(items.begin(), items.end(), [](const Item& i){ return i.cls == "orb"; });

    for (int i = 0; i < min((int)residents.size(), armor.size); ++i) {
        moveResident(items, weapon.name, armor.name, weapon.residents[i]);
    }

    for (int i = 0; i < min((int)residents.size(), orb.size); ++i) {
        moveResident(items, weapon.name, orb.name, weapon.residents[i]);
    }
}

void solve() {
    int n;
    cin >> n;
    vector<Item> items(n);
    for (auto& item : items) {
        cin >> item.name >> item.cls >> item.atk >> item.def >> item.res >> item.size;
    }

    int k;
    cin >> k;
    vector<Resident> residents(k);
    for (auto& resident : residents) {
        cin >> resident.name >> resident.type >> resident.bonus >> resident.home;
    }

    maximizeWeaponAttack(items, residents);
    maximizeArmorAndOrb(items, residents);

    for (auto& item : items) {
        cout << item.name << ' ' << item.residents.size();
        for (const auto& resident : item.residents) {
            cout << ' ' << resident;
        }
        cout << '\n';
    }
}

