#include <iostream>
#include <vector>
#include <queue>
using namespace std;

void solve(int n, int m, const vector<pair<int, int>>& edges) {
    vector<vector<int>> adj(n + 1);
    for (const auto& e : edges) {
        adj[e.first].push_back(e.second);
        adj[e.second].push_back(e.first);
    }

    queue<int> q;
    vector<bool> visited(n + 1, false);
    vector<int> degree(n + 1, 0);

    q.push(1);
    visited[1] = true;
    while (!q.empty()) {
        int u = q.front();
        q.pop();

        for (int v : adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                degree[u]++;
                degree[v]++;
                q.push(v);
            }
        }
    }

    int max_degree = *max_element(degree.begin(), degree.end());
    int min_degree = *min_element(degree.begin(), degree.end());

    if (min_degree == 0 || max_degree > 2) {
        cout << "unknown topology\n";
        return;
    }

    int one_count = 0, two_count = 0;
    for (int d : degree) {
        if (d == 1) one_count++;
        else if (d == 2) two_count++;
    }

    if (one_count == 1 && two_count == 2) {
        cout << "bus topology\n";
    } else if (two_count == n - 1) {
        cout << "ring topology\n";
    } else if (one_count == n - 1 && two_count == 1) {
        cout << "star topology\n";
    } else {
        cout << "unknown topology\n";
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<pair<int, int>> edges(m);
    for (int i = 0; i < m; ++i) {
        cin >> edges[i].first >> edges[i].second;
    }

    solve(n, m, edges);

    return 0;
}

