    int l, r;
    cin >> l >> r;
    ll n = r - l + 1;
    ll total = n * (n - 1) * (n - 2) / 6;
    ll bad = 0;

    for (int k = l + 2; k <= r; ++k) {
        const auto& d2 = divs[2 * k];
        vector<int> valid;
        valid.reserve(d2.size());
        for (int d : d2) {
            if (d >= l && d < k) valid.pb(d);
        }
        int m = (int)valid.size();
        if (m < 2) continue;

        ll cnt_le = 0;
        int j = m - 1;
        for (int i = 0; i < m; ++i) {
            while (j > i && valid[i] + valid[j] > k) --j;
            if (j <= i) break;
            cnt_le += (j - i);
        }

        const auto& d1 = divs[k];
        vector<int> valid1;
        valid1.reserve(d1.size());
        for (int d : d1) {
