#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>
#include <cmath>
using namespace std;

const int MAXN = 200005;
const long long MOD = 1e9 + 7;

long long factorial[MAXN];
long long inv_factorial[MAXN];

void precompute_factorials(int max_n) {
    factorial[0] = 1;
    for (int i = 1; i <= max_n; ++i) {
        factorial[i] = factorial[i - 1] * i % MOD;
    }
    inv_factorial[max_n] = modpow(factorial[max_n], MOD - 2);
    for (int i = max_n - 1; i >= 0; --i) {
        inv_factorial[i] = inv_factorial[i + 1] * (i + 1) % MOD;
    }
}

long long modpow(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp & 1) {
            result = result * base % mod;
        }
        base = base * base % mod;
        exp >>= 1;
    }
    return result;
}

long long gcd(long long a, long long b) {
    while (b != 0) {
        long long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;
}

long long count_triplets(int l, int r) {
    long long count = 0;
    for (int i = l; i <= r; ++i) {
        for (int j = i + 1; j <= r; ++j) {
            long long target = i + j;
            long long min_k = (target + lcm(i, j) - 1) / lcm(i, j);
            min_k = max(min_k, j + 1);
            if (min_k > r) continue;
            count += r - min_k + 1;
        }
    }
    return count;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    precompute_factorials(MAXN);

    int t;
    cin >> t;
    while (t--) {
        int l, r;
        cin >> l >> r;
        cout << count_triplets(l, r) << '\n';
    }

    return 0;
}

