#include <iostream>
#include <vector>
#include <bitset>
#include <cmath>
#include <algorithm>
using namespace std;

const int MOD = 1000000007;
const int MAXN = 1005;
typedef long long ll;
typedef double db;

struct Point {
    db x, y;
    Point(db x = 0, db y = 0) : x(x), y(y) {}
};

Point operator+(const Point &p, const Point &q) { return Point(p.x + q.x, p.y + q.y); }
Point operator-(const Point &p, const Point &q) { return Point(p.x - q.x, p.y - q.y); }
db dot(const Point &p, const Point &q) { return p.x * q.x + p.y * q.y; }
ll cross(const Point &p, const Point &q) { return ll(p.x) * q.y - ll(q.x) * p.y; }

bool are_collinear(const Point &p, const Point &q, const Point &r) {
    return cross(q - p, r - p) == 0;
}

int n;
Point points[MAXN];
bitset<MAXN> used;

void dfs(int pos, bitset<MAXN> &mask, vector<vector<int>> &adj, int &count) {
    if (pos >= adj.size()) {
        count = (count + 1) % MOD;
        return;
    }
    for (int next : adj[pos]) {
        if (!used[next]) {
            used[next] = true;
            mask.set(next);
            dfs(pos + 1, mask, adj, count);
            mask.reset(next);
            used[next] = false;
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n;
    for (int i = 0; i < n; ++i) {
        int a, b, c, d;
        cin >> a >> b >> c >> d;
        points[i].x = a / db(b);
        points[i].y = c / db(d);
    }

    vector<vector<int>> adj(n);
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            bool ok = true;
            for (int k = 0; k < n; ++k) {
                if (k != i && k != j && are_collinear(points[k], points[i], points[j])) {
                    ok = false;
                    break;
                }
            }
            if (ok) {
                adj[i].push_back(j);
                adj[j].push_back(i);
            }
        }
    }

    int total = 0;
    for (int start = 0; start < n; ++start) {
        bitset<MAXN> mask;
        used[start] = true;
        mask.set(start);
        int count = 0;
        dfs(0, mask, adj, count);
        total = (total + count) % MOD;
        used.reset(start);
    }

    cout << total << '\n';

    return 0;
}

