using namespace std;

const int MOD = 998244353;

int modpow(int base, int exp, int mod) {
    int res = 1;
    base %= mod;
    while (exp > 0) {
        if (exp & 1)
            res = (res * base) % mod;
        base = (base * base) % mod;
        exp >>= 1;
    }
    return res;
}

int modinv(int a, int mod) {
    return modpow(a, mod - 2, mod);
}

struct Fraction {
    int num, den;

    Fraction(int n = 0, int d = 1) : num(n), den(d) {}

    void normalize() {
        if (den < 0) {
            num = -num;
            den = -den;
        }
        int g = gcd(abs(num), abs(den));
        num /= g;
        den /= g;
    }

    Fraction operator+(const Fraction& other) const {
        int new_num = num * other.den + other.num * den;
        int new_den = den * other.den;
        Fraction f(new_num, new_den);
        f.normalize();
        return f;
    }

    Fraction operator*(const Fraction& other) const {
        int new_num = num * other.num;
        int new_den = den * other.den;
        Fraction f(new_num, new_den);
        f.normalize();
        return f;
    }
};

Fraction expected_turns(const vector<int>& s) {
    int n = s.size();
    vector<vector<Fraction>> dp(2, vector<Fraction>(1 << 30, Fraction()));
    vector<vector<bool>> known(2, vector<bool>(1 << 30, false));

    auto update = [&](int player, int mask, const Fraction& val) {
        if (!known[player][mask]) {
            dp[player][mask] = val;
            known[player][mask] = true;
        } else {
            dp[player][mask] += val;
        }
    };

    // Initialize for player 1 (Alice) starting with no information
    update(0, 0, Fraction(1, 1));

    for (int i = 0; i < n; ++i) {
        vector<vector<Fraction>> ndp(2, vector<Fraction>(1 << 30, Fraction()));
        vector<vector<bool>> nknown(2, vector<bool>(1 << 30, false));

        for (int j = 0; j <= 30; ++j) {
            for (int msk = 0; msk < (1 << 30); ++msk) {
                if (!known[0][msk])
                    continue;

                Fraction pr = dp[0][msk];
                int cnt = __builtin_popcount(msk);
                int max_bit = -1;
                for (int k = 0; k < 30; ++k) {
                    if ((msk >> k) & 1) {
                        max_bit = k;
                    }
                }

                if (max_bit == -1) {
                    // Both are zero, trivial case
                    ndp[1][msk] += pr;
                } else {
                    int bit_mask = 1 << max_bit;
                    int bit_cnt = __builtin_popcount(bit_mask & msk);

                    // Player 1 can guess if he knows the exact value
                    if (bit_cnt == 1 && !(msk & (bit_mask ^ (s[i] & bit_mask)))) {
                        Fraction guess_pr = pr / 2;
                        ndp[1][msk] += guess_pr;
                        ndp[0][(msk & ~bit_mask)] += guess_pr;
                    } else {
                        // Player 1 passes
                        ndp[0][(msk & ~(1 << max_bit))] += pr;
                    }
                }
            }
        }

        swap(dp, ndp);
        swap(known, nknown);
    }

    // Sum up all outcomes for player 1 knowing the answer
    Fraction ans = Fraction();
    for (int msk = 0; msk < (1 << 30); ++msk) {
        if (known[1][msk]) {
            ans += dp[1][msk];
        }
    }

    // Normalize and invert denominator
    ans.normalize();
    int inv_den = modinv(ans.den, MOD);
    ans.num = (long long)ans.num * inv_den % MOD;

    return ans;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
