    while (t--) {
        int n;
        cin >> n;
        vector<int> s(n);
        for (int i = 0; i < n; ++i) {
            cin >> s[i];
        }

        Fraction exp_turns = expected_turns(s);
        cout << exp_turns.num << "\n";
    }

    return 0;
}

