#include <bits/stdc++.h>
using namespace std;

#define ll long long
#define pb push_back
#define mp make_pair

const int MAXN = 3e5 + 10;
int n, q;
int arr[MAXN];
int orig[MAXN];

struct Node {
    ll val;
    int pos;
};

bool cmp(Node &a, Node &b) {
    return a.val > b.val;
}

vector<Node> nodes;

void init(int idx, int tl, int tr, vector<int> &p, vector<Node> &seg, vector<bool> &lazy) {
    seg[idx].val = p[tl];
    seg[idx].pos = tl;
    if (tl == tr)
        return;
    int tm = (tl + tr) / 2;
    init(idx * 2, tl, tm, p, seg, lazy);
    init(idx * 2 + 1, tm + 1, tr, p, seg, lazy);
}

Node query(int idx, int tl, int tr, int l, int r, vector<Node> &seg, vector<bool> &lazy) {
    if (lazy[idx]) {
        seg[idx].val *= -1;
        if (tl != tr) {
            lazy[idx * 2] = !lazy[idx * 2];
            lazy[idx * 2 + 1] = !lazy[idx * 2 + 1];
        }
        lazy[idx] = false;
    }
    if (l > tr || r < tl)
        return {0, 0};
    if (l <= tl && tr <= r)
        return seg[idx];
    int tm = (tl + tr) / 2;
    Node left = query(idx * 2, tl, tm, l, r, seg, lazy);
    Node right = query(idx * 2 + 1, tm + 1, tr, l, r, seg, lazy);
    if (left.val > right.val)
        return left;
    return right;
}

void update(int idx, int tl, int tr, int pos, ll val, vector<Node> &seg, vector<bool> &lazy) {
    if (lazy[idx]) {
        seg[idx].val *= -1;
        if (tl != tr) {
            lazy[idx * 2] = !lazy[idx * 2];
            lazy[idx * 2 + 1] = !lazy[idx * 2 + 1];
        }
        lazy[idx] = false;
    }
    if (tl == tr) {
        seg[idx].val = val;
        seg[idx].pos = pos;
        return;
    }
    int tm = (tl + tr) / 2;
    if (pos <= tm)
        update(idx * 2, tl, tm, pos, val, seg, lazy);
    else
        update(idx * 2 + 1, tm + 1, tr, pos, val, seg, lazy);
    if (seg[idx * 2].val > seg[idx * 2 + 1].val) {
        seg[idx].val = seg[idx * 2].val;
        seg[idx].pos = seg[idx * 2].pos;
    } else {
        seg[idx].val = seg[idx * 2 + 1].val;
        seg[idx].pos = seg[idx * 2 + 1].pos;
    }
}

ll solve(vector<int> &p) {
    vector<Node> seg(4 * n);
    vector<bool> lazy(4 * n, false);
    init(1, 0, n - 1, p, seg, lazy);

    ll ans = 0;
    for (int i = 0; i < n; ++i) {
        Node res = query(1, 0, n - 1, i, n - 1, seg, lazy);
        ans += res.val;
    }
    return ans;
}

void process() {
    cin >> n >> q;
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
        orig[i] = arr[i];
    }

    sort(arr, arr + n);
    vector<int> p(n);
    p[0] = arr[0];
    for (int i = 1; i < n; ++i)
        p[i] = arr[i] - arr[i - 1];

    nodes.clear();
    for (int i = 0; i < n; ++i)
        nodes.pb({p[i], i});

    sort(nodes.begin(), nodes.end(), cmp);

    vector<int> mapping(n);
    for (int i = 0; i < n; ++i)
        mapping[nodes[i].pos] = i;

    vector<int> new_order(n);
    for (int i = 0; i < n; ++i)
        new_order[mapping[i]] = i;

    ll cur_ans = solve(p);
    cout << cur_ans << ' ';

    while (q--) {
        int l, r;
        cin >> l >> r;
        --l, --r;

        int old_l = orig[l], old_r = orig[r];
        orig[l] = old_r;
        orig[r] = old_l;

        int pos_l = mapping[l];
        int pos_r = mapping[r];

        int new_pos_l = mapping[pos_l];
        int new_pos_r = mapping[pos_r];

        mapping[l] = new_pos_r;
        mapping[r] = new_pos_l;

        mapping[new_pos_l] = l;
        mapping[new_pos_r] = r;

        swap(new_order[new_pos_l], new_order[new_pos_r]);

        int val_l = new_order[new_pos_l];
        int val_r = new_order[new_pos_r];

        int old_p_l = pos_l - val_l;
        int old_p_r = pos_r - val_r;

        int new_p_l = new_pos_r - val_l;
        int new_p_r = new_pos_l - val_r;

        int delta_l = new_p_l - old_p_l;
        int delta_r = new_p_r - old_p_r;

        p[val_l] -= delta_l;
        p[val_r] += delta_r;

        ll next_ans = solve(p);
        cout << next_ans << ' ';
    }
    cout << '\n';
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    cin >> t;
    while (t--)
        process();
    return 0;
}

