// helper: squared distance between two planets
ll dist2(const vll& x, const vll& y, const vll& z, int i, int j) {
    ll dx = x[i] - x[j];
    ll dy = y[i] - y[j];
    ll dz = z[i] - z[j];
    return dx * dx + dy * dy + dz * dz;
}

void solve() {
    int n;
    cin >> n;
    vll x(n), y(n), z(n);
    for (int i = 0; i < n; ++i) {
        cin >> x[i] >> y[i] >> z[i];
    }

    const double INF = 1e18;
    vector<double> t(n, INF);
    vector<bool> vis(n, false);
    t[0] = 0.0;

    for (int iter = 0; iter < n; ++iter) {
        int u = -1;
        double best = INF;
        for (int i = 0; i < n; ++i) {
            if (!vis[i] && t[i] < best) {
                best = t[i];
                u = i;
            }
        }
        if (u == -1) break;
        vis[u] = true;
        for (int v = 0; v < n; ++v) {
            if (!vis[v]) {
                double d = sqrt((double)dist2(x, y, z, u, v));
                if (t[u] + d < t[v]) {
                    t[v] = t[u] + d;
                }
            }
        }
    }

    double ans = INF;
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            double d = sqrt((double)dist2(x, y, z, i, j));
            if (fabs(t[i] - t[j]) < d - 1e-12) {
                double cand = (t[i] + t[j] + d) / 2.0;
                if (cand < ans) ans = cand;
            }
        }
    }

    cout << ans << endl;
}

int main() {
    fastio;
    cout << fixed << setprecision(10);
    solve();
    return 0;
}

