#include <iostream>
#include <vector>
#include <queue>
#include <cmath>
#include <unordered_set>
#include <iomanip>

using namespace std;

struct Point {
    double x, y, z;
};

double dist(const Point& p1, const Point& p2) {
    return sqrt((p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y) + (p1.z - p2.z) * (p1.z - p2.z));
}

struct State {
    int id;
    double time;
    Point pos;
    bool operator<(const State& other) const {
        return time > other.time;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<Point> planets(n);
    for (int i = 0; i < n; ++i) {
        cin >> planets[i].x >> planets[i].y >> planets[i].z;
    }

    vector<vector<double>> d(n, vector<double>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            d[i][j] = dist(planets[i], planets[j]);
            d[j][i] = d[i][j];
        }
    }

    priority_queue<State> pq;
    unordered_set<string> occupied;

    for (int i = 1; i < n; ++i) {
        double t = d[0][i];
        pq.push({i, t, planets[i]});
        occupied.insert(to_string(i) + "," + to_string(t));
    }

    while (!pq.empty()) {
        auto [id, time, pos] = pq.top();
        pq.pop();

        for (int j = 0; j < n; ++j) {
            if (j == id) continue;
            double dt = d[id][j];
            double next_time = time + dt;
            string key = to_string(j) + "," + to_string(next_time);
            if (occupied.find(key) != occupied.end()) {
                continue; // Collision detected
            }
            occupied.insert(key);
            pq.push({j, next_time, planets[j]});
        }
    }

    cout << fixed << setprecision(15);
    cout << pq.top().time << endl;

    return 0;
}

