#include <iostream>
#include <vector>
#include <algorithm>
#include <unordered_map>
using namespace std;

bool canFormThreePlans(const vector<int>& h) {
    int n = h.size();
    unordered_map<int, vector<int>> groups;

    // Group tasks by difficulty
    for (int i = 0; i < n; ++i) {
        groups[h[i]].push_back(i + 1);
    }

    // Check if each group has enough tasks to form three distinct permutations
    for (const auto& group : groups) {
        if (group.second.size() < 3) {
            return false;
        }
    }
    return true;
}

void solve(const vector<int>& h) {
    int n = h.size();
    unordered_map<int, vector<int>> groups;

    // Group tasks by difficulty
    for (int i = 0; i < n; ++i) {
        groups[h[i]].push_back(i + 1);
    }

    vector<vector<int>> plans(3, vector<int>(n));

    // Fill plans with distinct permutations for each group
    for (auto& [difficulty, tasks] : groups) {
        int sz = tasks.size();
        for (int i = 0; i < 3 && i < sz; ++i) {
            for (int j = 0; j < sz; ++j) {
                plans[i][j] = tasks[j];
            }
        }
    }

    // Print result
    cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        cout << plans[0][i] << " ";
    }
    cout << "\n";
    for (int i = 0; i < n; ++i) {
        cout << plans[1][i] << " ";
    }
    cout << "\n";
    for (int i = 0; i < n; ++i) {
        cout << plans[2][i] << " ";
    }
    cout << "\n";
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> h(n);
    for (int i = 0; i < n; ++i) {
        cin >> h[i];
    }

    if (!canFormThreePlans(h)) {
        cout << "NO\n";
    } else {
        solve(h);
    }

    return 0;
}

