bool canAssign(vector<ll>& times, vector<pair<int, int>>& sortedLemmings, int k, ll maxTime) {
    int n = sortedLemmings.size();
    vector<bool> assigned(n + 1, false);
    for (int i = 0; i < n && k > 0; ++i) {
        int idx = sortedLemmings[i].second;
        if (!assigned[idx]) {
            assigned[idx] = true;
            --k;
        }
    }
    return k == 0;
}

vector<int> findOptimalJump(int n, int k, int h, vector<int>& m, vector<int>& v) {
    vector<vector<ll>> times(n, vector<ll>(n + 1));
    for (int i = 0; i < n; ++i) {
        for (int j = 1; j <= n; ++j) {
            times[i][j] = static_cast<ll>(j * h) / v[i];
        }
    }

    vector<pair<int, int>> sortedLemmings(n);
    for (int i = 0; i < n; ++i) {
        sortedLemmings[i] = {m[i], i};
    }
    sort(sortedLemmings.begin(), sortedLemmings.end());

    ll left = 0, right = 1e18, ans = -1;
    while (left <= right) {
        ll mid = left + (right - left) / 2;
        if (canAssign(times, sortedLemmings, k, mid)) {
            ans = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    vector<int> result(k);
    for (int i = 0; i < n && k > 0; ++i) {
        int idx = sortedLemmings[i].second;
        for (int j = 1; j <= n; ++j) {
            if (times[idx][j] <= ans) {
                result[k - 1] = idx + 1;
                --k;
                break;
            }
        }
    }
    return result;
}

int main() {
    ios::sync_with_stdio(false);
