using namespace std;

void solve(int n, const vector<int>& snacks) {
    set<int> placed;
    vector<vector<int>> result(n);

    for (int i = 0; i < n; ++i) {
        int current = snacks[i];

        // Check if all smaller snacks are already placed
        bool can_place = true;
        for (int s : placed) {
            if (s > current) {
                can_place = false;
                break;
            }
        }

        if (can_place) {
            placed.insert(current);
            result[i].push_back(current);

            // Place all smaller snacks on top of the current one
            for (auto rit = placed.rbegin(); rit != placed.rend(); ++rit) {
                if (*rit == current) break;
                result[i].push_back(*rit);
                placed.erase(rit.base());
            }
        } else {
            // If we cannot place the current snack, skip it
        }
    }

    for (const auto& row : result) {
        for (int s : row) {
            cout << s << " ";
        }
        cout << endl;
    }
}

