    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> snacks(n);
    for (int i = 0; i < n; ++i) {
        cin >> snacks[i];
    }

    solve(n, snacks);

    return 0;
}

