    vector<int> b(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        cin >> b[i];
    }

    unordered_set<int> unsorted;
    for (int i = 0; i < n; ++i) {
        unsorted.insert(i + 1);
    }

    int operations = 0;
    vector<int> op_sequence;

    while (!unsorted.empty()) {
        auto min_unsorted = *min_element(unsorted.begin(), unsorted.end());
        unsorted.erase(min_unsorted);

        // Find x for a_x = min_unsorted
        int x = 0;
        for (int i = 0; i < n; ++i) {
            if (a[i] == min_unsorted) {
                x = i + 1;
                break;
            }
        }

        // Find y for b_y = min_unsorted
        int y = 0;
        for (int i = 0; i < n; ++i) {
            if (b[i] == min_unsorted) {
                y = i + 1;
                break;
            }
        }

        // Swap a_i with a_x
        swap(a[min_unsorted - 1], a[x - 1]);

        // Swap b_i with b_y
        swap(b[min_unsorted - 1], b[y - 1]);

        // Add operations to sequence
        if (min_unsorted != x) {
            op_sequence.push_back(x);
            operations++;
        }
        if (min_unsorted != y) {
            op_sequence.push_back(y);
            operations++;
        }
    }

    cout << operations << endl;
    for (int op : op_sequence) {
        cout << op << " ";
    }
    cout << endl;
}

