#include <bits/stdc++.h>
using namespace std;

const int MOD = 1e9 + 7;

// Function to compute (base^exp) % MOD using fast exponentiation
int power(int base, long long exp) {
    int res = 1;
    while (exp > 0) {
        if (exp & 1) {
            res = (res * base) % MOD;
        }
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

// Function to find the highest power of prime p dividing x
int highest_power(long long x, int p) {
    int count = 0;
    while (x % p == 0) {
        x /= p;
        ++count;
    }
    return count;
}

// Function to compute f(x, y)
long long f(int x, long long y) {
    vector<int> primes;
    for (int p = 2; p * p <= x; ++p) {
        if (x % p == 0) {
            primes.push_back(p);
            while (x % p == 0) {
                x /= p;
            }
        }
    }
    if (x > 1) {
        primes.push_back(x);
    }

    long long result = 1;
    for (int p : primes) {
        int k = highest_power(y, p);
        result = (result * power(p, k)) % MOD;
    }
    return result;
}

// Function to compute the overall product f(x, 1) * f(x, 2) * ... * f(x, n) % MOD
long long solve(int x, long long n) {
    vector<int> primes;
    for (int p = 2; p * p <= x; ++p) {
        if (x % p == 0) {
            primes.push_back(p);
            while (x % p == 0) {
                x /= p;
            }
        }
    }
    if (x > 1) {
        primes.push_back(x);
    }

    long long result = 1;
    for (int p : primes) {
        int k = 0;
        for (long long i = 1; i <= n; ++i) {
            k += highest_power(i, p);
        }
        result = (result * power(p, k)) % MOD;
    }
    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int x;
    long long n;
    cin >> x >> n;

    cout << solve(x, n) << '\n';

    return 0;
}

