const int MOD = 1000000007;
const int MAXN = 100005;
const int MAXK = 101;

int C[MAXN][MAXK];

void preprocess_binomials(int n) {
    C[0][0] = 1;
    for (int i = 1; i < n; ++i) {
        C[i][0] = 1;
        for (int j = 1; j <= min(i, MAXK); ++j) {
            C[i][j] = (C[i-1][j-1] + C[i-1][j]) % MOD;
        }
    }
}

void solve(vector<int>& a, vector<pair<int, pair<int, int>>>& queries) {
    int n = a.size();
    preprocess_binomials(n);

    for (auto& q : queries) {
        int l = q.first, r = q.second.first, k = q.second.second;
        for (int j = l; j <= r; ++j) {
            int offset = j - l + k;
            if (offset >= 0 && offset < n) {
                a[offset] = (a[offset] + C[r - l][k]) % MOD;
            }
        }
    }
}

