int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> widths(n);
    for (int i = 0; i < n; ++i) {
        cin >> widths[i];
    }
    string order;
    cin >> order;

    vector<bool> seats_available(n, true);
    set<pair<int, int>> available_rows; // pair(width, row)
    for (int i = 0; i < n; ++i) {
        available_rows.insert({widths[i], i});
    }

    vector<int> result(2 * n);
    for (int j = 0; j < 2 * n; ++j) {
        char type = order[j];
        if (type == '0') { // introvert
            auto [width, row] = *available_rows.begin();
            result[j] = row + 1;
            available_rows.erase(available_rows.begin());
            seats_available[row] &= false; // mark left seat as taken
            if (!seats_available[row]) {
                available_rows.erase(available_rows.find({widths[row], row}));
            }
        } else { // extrovert
            auto it = available_rows.rbegin();
            while (it != available_rows.rend()) {
                auto [width, row] = *it;
                if (seats_available[row] == true) {
                    result[j] = row + 1;
                    available_rows.erase(it.base());
                    seats_available[row] &= false; // mark right seat as taken
                    if (!seats_available[row]) {
                        available_rows.erase(available_rows.find({widths[row], row}));
                    }
                    break;
                }
                ++it;
            }
        }
    }

    for (int i = 0; i < 2 * n; ++i) {
        cout << result[i] << " ";
    }
    return 0;
}

