char solve(const vector<string>& descriptions) {
    int n = descriptions.size();
    vector<int> lengths(n);

    // Extract lengths
    for (int i = 0; i < n; ++i) {
        lengths[i] = descriptions[i].size();
    }

    // Find min and max lengths
    int min_length = *min_element(lengths.begin(), lengths.end());
    int max_length = *max_element(lengths.begin(), lengths.end());

    // Count great choices
    int great_count = 0;
    for (int len : lengths) {
        if (len <= min_length / 2 || len >= max_length * 2) {
            ++great_count;
        }
    }

    // Select the choice
    if (great_count == 1) {
        for (int i = 0; i < n; ++i) {
            if (lengths[i] <= min_length / 2 || lengths[i] >= max_length * 2) {
                return 'A' + i;
            }
        }
    }
    return 'C';
}

