    cin.tie(nullptr);

    string line;
    getline(cin, line); // Consume "A."
    vector<string> descriptions(4);
    for (int i = 0; i < 4; ++i) {
        getline(cin, descriptions[i]);
    }

    cout << solve(descriptions) << endl;

    return 0;
}

