const int MAXN = 10005;

int n, q;
vector<int> tree[4 * MAXN];
bitset<MAXN> ans;

void add_op(int node, int l, int r, int ql, int qr, int x) {
    if (ql <= l && r <= qr) {
        tree[node].pb(x);
        return;
    }
    int mid = (l + r) / 2;
    if (ql <= mid) add_op(node * 2, l, mid, ql, qr, x);
    if (qr > mid) add_op(node * 2 + 1, mid + 1, r, ql, qr, x);
}

void dfs(int node, int l, int r, bitset<MAXN> cur) {
    for (int x : tree[node]) {
        cur |= (cur << x);
    }
    if (l == r) {
        ans |= cur;
        return;
    }
    int mid = (l + r) / 2;
    dfs(node * 2, l, mid, cur);
    dfs(node * 2 + 1, mid + 1, r, cur);
}

