using namespace std;

#define ll long long

ll gcd(ll a, ll b) {
    return b == 0 ? a : gcd(b, a % b);
}

void solve() {
    int n;
    cin >> n;
    vector<ll> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    vector<int> x(3), y(3);
    for (int i = 0; i < 3; ++i) {
        cin >> x[i] >> y[i];
    }

    vector<ll> min_moves(n), max_moves(n);

    // Precompute min and max moves for each castle
    for (int i = 0; i < n; ++i) {
        ll val = a[i];

        // Mixed attack
        if (val >= x[0]) {
            min_moves[i] += val / x[0];
            max_moves[i] += val / x[0];
            if (val % x[0] != 0) {
                min_moves[i]++;
                max_moves[i]++;
            }
        } else {
            min_moves[i] = 0;
            max_moves[i] = 0;
        }

        // Infantry attack
        if (val >= y[0]) {
            min_moves[i] += val / y[0];
            max_moves[i] += val / y[0];
            if (val % y[0] != 0) {
                min_moves[i]++;
                max_moves[i]++;
            }
        }

        // Cavalry attack
        if (val >= y[1]) {
            min_moves[i] += val / y[1];
            max_moves[i] += val / y[1];
            if (val % y[1] != 0) {
                min_moves[i]++;
                max_moves[i]++;
            }
        }

        // Mixed attack (second)
        if (val >= x[1]) {
            min_moves[i] += val / x[1];
            max_moves[i] += val / x[1];
            if (val % x[1] != 0) {
                min_moves[i]++;
                max_moves[i]++;
            }
        }

        // Infantry attack (second)
        if (val >= y[2]) {
            min_moves[i] += val / y[2];
            max_moves[i] += val / y[2];
            if (val % y[2] != 0) {
                min_moves[i]++;
                max_moves[i]++;
            }
        }
    }

    // Total min and max moves
    ll total_min = accumulate(min_moves.begin(), min_moves.end(), 0LL);
    ll total_max = accumulate(max_moves.begin(), max_moves.end(), 0LL);

    // Check if total moves is odd
    if ((total_min + total_max) % 2 != 0) {
        cout << "0\n";
    } else {
        cout << (total_max - total_min + 1) << "\n";
    }
}

