#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

void solve() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int& x : a) cin >> x;

    // Calculate prefix sums
    vector<long long> prefix(n + 1);
    for (int i = 1; i <= n; ++i) {
        prefix[i] = prefix[i - 1] + a[i - 1];
    }

    // Find sign change points
    vector<int> sign_changes;
    for (int i = 1; i <= n; ++i) {
        if ((prefix[i] > 0 && prefix[i - 1] <= 0) || (prefix[i] < 0 && prefix[i - 1] >= 0)) {
            sign_changes.push_back(i);
        }
    }

    // Check if total sum is even
    if ((prefix[n] % 2 != 0)) {
        cout << "-1\n";
        return;
    }

    // Construct segments
    int k = sign_changes.size();
    cout << k << '\n';
    for (int i = 0; i < k; ++i) {
        cout << (i == 0 ? 1 : sign_changes[i]) << ' ' << sign_changes[i] << '\n';
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        solve();
    }

    return 0;
}
